import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { useState, useRef, useEffect, useCallback } from 'react';

// Use environment variable for API Key
const API_KEY = process.env.API_KEY || '';

interface UseGeminiLiveReturn {
  isConnected: boolean;
  isTalking: boolean; // Is the AI currently speaking
  connect: () => Promise<void>;
  disconnect: () => void;
  error: string | null;
}

export const useGeminiLive = (): UseGeminiLiveReturn => {
  const [isConnected, setIsConnected] = useState(false);
  const [isTalking, setIsTalking] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);

  // Audio Playback State
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Cleanup function
  const cleanup = useCallback(() => {
    // Stop microphone stream
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }

    // Disconnect audio nodes
    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (sourceRef.current) {
      sourceRef.current.disconnect();
      sourceRef.current = null;
    }

    // Close AudioContexts
    if (inputAudioContextRef.current) {
      inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      outputAudioContextRef.current.close();
      outputAudioContextRef.current = null;
    }

    // Stop all playing audio
    audioSourcesRef.current.forEach(source => {
      try { source.stop(); } catch(e) {}
    });
    audioSourcesRef.current.clear();

    sessionPromiseRef.current = null;
    setIsConnected(false);
    setIsTalking(false);
  }, []);

  const connect = async () => {
    if (!API_KEY) {
      setError("API Key not found.");
      return;
    }
    setError(null);

    try {
      const ai = new GoogleGenAI({ apiKey: API_KEY });

      // Initialize Audio Contexts
      inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      // Get Microphone Stream
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const config = {
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
            console.log('Gemini Live Connection Opened');
            setIsConnected(true);

            if (!inputAudioContextRef.current || !streamRef.current) return;

            // Setup Input Processing
            const source = inputAudioContextRef.current.createMediaStreamSource(streamRef.current);
            sourceRef.current = source;

            const processor = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmData = convertFloat32ToInt16(inputData); // Custom conversion
              const base64Data = arrayBufferToBase64(pcmData);

              sessionPromiseRef.current?.then(session => {
                session.sendRealtimeInput({
                  media: {
                    mimeType: 'audio/pcm;rate=16000',
                    data: base64Data
                  }
                });
              });
            };

            source.connect(processor);
            processor.connect(inputAudioContextRef.current.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Audio Output
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio && outputAudioContextRef.current) {
              setIsTalking(true);
              const ctx = outputAudioContextRef.current;

              // Decode
              const audioData = base64ToArrayBuffer(base64Audio);
              const audioBuffer = await decodeAudioData(audioData, ctx, 24000, 1);

              // Schedule
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);

              source.onended = () => {
                audioSourcesRef.current.delete(source);
                if (audioSourcesRef.current.size === 0) {
                   setIsTalking(false);
                }
              };

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              audioSourcesRef.current.add(source);
            }

            // Handle Interruptions
            if (message.serverContent?.interrupted) {
              audioSourcesRef.current.forEach(src => {
                try { src.stop(); } catch(e) {}
              });
              audioSourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsTalking(false);
            }
          },
          onclose: () => {
            console.log('Gemini Live Connection Closed');
            cleanup();
          },
          onerror: (err: any) => {
            console.error('Gemini Live Error', err);
            setError("Connection error.");
            cleanup();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
          },
          systemInstruction: `You are the friendly and helpful voice assistant for the Christ Life Bweyogerere (CLB) church app. 
          Help users find features like 'Live Stream', 'Bible', 'Music', 'Groups' (which includes MCs, Media Team, Worship Team, Dance Team, Kids Church, Admin).
          If they ask about donations, guide them to the Giving section. 
          Keep answers brief, warm, and encouraging.
          The app has sections: Home (Adverts), Bible (Luganda/English), Groups (Ministries), Music (Worship Harvest), Giving.`
        }
      };

      sessionPromiseRef.current = ai.live.connect(config);

    } catch (err) {
      console.error("Failed to connect:", err);
      setError("Failed to start voice assistant.");
      cleanup();
    }
  };

  const disconnect = () => {
     // There isn't a direct session.close() exposed easily on the promise without awaiting it, 
     // but cleaning up the socket/contexts effectively kills it from client side.
     // In a real robust app, we'd handle the session object more carefully.
     cleanup();
  };

  useEffect(() => {
    return () => cleanup();
  }, [cleanup]);

  return { isConnected, isTalking, connect, disconnect, error };
};

// --- Helpers ---

function convertFloat32ToInt16(float32Array: Float32Array): ArrayBuffer {
  const int16Array = new Int16Array(float32Array.length);
  for (let i = 0; i < float32Array.length; i++) {
    let s = Math.max(-1, Math.min(1, float32Array[i]));
    int16Array[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
  }
  return int16Array.buffer;
}

function arrayBufferToBase64(buffer: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function base64ToArrayBuffer(base64: string): ArrayBuffer {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes.buffer;
}

async function decodeAudioData(
  arrayBuffer: ArrayBuffer,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(arrayBuffer);
  const frameCount = dataInt16.length / numChannels;
  const audioBuffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = audioBuffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return audioBuffer;
}

import React from 'react';
import { Home, BookOpen, Users, Music, Heart } from 'lucide-react';
import { View } from '../types';

interface BottomNavProps {
  currentView: View;
  setView: (view: View) => void;
}

export const BottomNav: React.FC<BottomNavProps> = ({ currentView, setView }) => {
  const navItems = [
    { view: View.HOME, label: 'Home', icon: Home },
    { view: View.BIBLE, label: 'Bible', icon: BookOpen },
    { view: View.GROUPS, label: 'Groups', icon: Users },
    { view: View.MUSIC, label: 'Music', icon: Music },
    { view: View.GIVING, label: 'Give', icon: Heart },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 px-4 py-2 flex justify-between items-center z-40 pb-safe">
      {navItems.map((item) => {
        const isActive = currentView === item.view || 
          (item.view === View.GROUPS && currentView.startsWith('GROUP_'));

        return (
          <button
            key={item.label}
            onClick={() => setView(item.view)}
            className={`flex flex-col items-center space-y-1 w-16 transition-colors duration-200 ${
              isActive ? 'text-indigo-600' : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            <item.icon size={24} strokeWidth={isActive ? 2.5 : 2} />
            <span className="text-[10px] font-medium">{item.label}</span>
          </button>
        );
      })}
    </div>
  );
};

import React, { useState } from 'react';
import { Mic, X, Loader2, Volume2 } from 'lucide-react';
import { useGeminiLive } from '../services/geminiLive';

export const VoiceAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const { isConnected, isTalking, connect, disconnect, error } = useGeminiLive();

  const handleToggle = async () => {
    if (isOpen) {
      disconnect();
      setIsOpen(false);
    } else {
      setIsOpen(true);
      await connect();
    }
  };

  return (
    <>
      {/* FAB */}
      <button
        onClick={handleToggle}
        className={`fixed bottom-20 right-4 p-4 rounded-full shadow-xl z-50 transition-all duration-300 transform hover:scale-105 ${
          isOpen ? 'bg-red-500' : 'bg-indigo-600'
        } text-white`}
      >
        {isOpen ? <X size={24} /> : <Mic size={24} />}
      </button>

      {/* Overlay Modal */}
      {isOpen && (
        <div className="fixed bottom-36 right-4 w-64 bg-white rounded-2xl shadow-2xl p-6 z-50 border border-gray-100 animate-fade-in-up">
          <div className="flex flex-col items-center text-center space-y-4">
            <h3 className="font-semibold text-gray-800">CLB Assistant</h3>

            {error ? (
              <p className="text-sm text-red-500">{error}</p>
            ) : !isConnected ? (
              <div className="flex items-center space-x-2 text-gray-500">
                 <Loader2 className="animate-spin" size={20} />
                 <span className="text-sm">Connecting...</span>
              </div>
            ) : (
              <div className="relative">
                 <div className={`w-16 h-16 rounded-full flex items-center justify-center transition-colors duration-300 ${isTalking ? 'bg-indigo-100' : 'bg-gray-100'}`}>
                    <Mic className={`${isTalking ? 'text-indigo-600 animate-pulse' : 'text-gray-400'}`} size={32} />
                 </div>
                 {isTalking && (
                   <div className="absolute -top-1 -right-1 bg-green-500 rounded-full p-1">
                     <Volume2 size={12} className="text-white" />
                   </div>
                 )}
              </div>
            )}

            <p className="text-xs text-gray-500">
              {isConnected 
                ? (isTalking ? "I'm speaking..." : "Listening...") 
                : "Initializing..."}
            </p>
          </div>
        </div>
      )}
    </>
  );
};

