export const getLugandaVerse = (query: string): string | null => {
  // Normalize query like "John 3:16" to match "Yokaana" "3:16"
  const parts = query.split(' ');
  if (parts.length < 2) return null;

  const bookInput = parts[0].toLowerCase();
  const ref = parts[1];

  // Map English book names to Luganda keys
  const mapping: Record<string, string> = {
    "genesis": "Lubereberye",
    "psalms": "Zabbuli",
    "proverbs": "Engero",
    "isaiah": "Isaaya",
    "matthew": "Matayo",
    "john": "Yokaana",
    "romans": "Abarumi",
    "philippians": "Abafilipi",
    "lubereberye": "Lubereberye",
    "zabbuli": "Zabbuli",
    "engero": "Engero",
    "isaaya": "Isaaya",
    "matayo": "Matayo",
    "yokaana": "Yokaana",
    "abarumi": "Abarumi",
    "abafilipi": "Abafilipi"
  };

  const lugandaBook = mapping[bookInput];
  if (lugandaBook && LUGANDA_BIBLE_DATA[lugandaBook]) {
    return LUGANDA_BIBLE_DATA[lugandaBook][ref] || null;
  }

  return null;
};

import React, { useState, useEffect } from 'react';
import { Search, Book, RefreshCw, ChevronRight, BookOpen } from 'lucide-react';
